	&lt;li&gt;&lt;span&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;WHO&amp;rsquo;s Priority Pathogen List:&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;​​&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;Disease X was included in the WHO&amp;#39;s &lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;Blueprint for Priority Diseases in 2018&lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt; to emphasize the need for preparedness against unknown health threats.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;The list also includes &lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;Ebola, Nipah, Marburg, Zika, and Lassa fever&lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
