	&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;Emergence of Disease X:&lt;/span&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;Likely sources include &lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;zoonotic spillovers&lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt; (diseases transmitted from animals to humans), mutations, or laboratory mishaps.&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;Climate change, deforestation, and increased human-wildlife interactions amplify risks.&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;Significance of the Term:&lt;/span&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;​&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;It highlights gaps in &lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;global pandemic preparedness&lt;/span&gt;&lt;span style=&quot; background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline; text-wrap-mode: wrap;&quot;&gt;, including surveillance, healthcare infrastructure, and rapid vaccine/diagnostic development.&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;विकल्प 2&lt;/span&gt;&lt;/u&gt;&amp;nbsp;है।&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;विश्व स्वास्थ्य संगठन (WHO) ने 2018 में &amp;quot;रोग X&amp;quot; शब्द को एक अप्रत्याशित और अज्ञात रोगज़नक़ के लिए गढ़ा था, जो एक विनाशकारी वैश्विक स्वास्थ्य संकट को जन्म दे सकता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex; gap: 6px; align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul dir=&quot;ltr&quot; style=&quot;color: rgb(33, 37, 41);&quot;&gt;
	&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;रोग X की परिभाषा:&lt;/span&gt;&lt;/span&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;रोग X कोई विशिष्ट बीमारी नहीं है, बल्कि एक&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;संकल्पनात्मक प्लेसहोल्डर है&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;जो किसी अज्ञात रोगाणु के जोखिम को दर्शाता है जो महामारी पैदा करने में सक्षम है।&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;COVID-19 को व्यापक रूप से रोग X का पहला वास्तविक-विश्व उदाहरण माना जाता है&amp;nbsp;&lt;em&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;। इसलिए, बिंदु 2 सही है।&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/em&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;WHO की प्राथमिकता रोगजनक सूची:&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;अज्ञात स्वास्थ्य खतरों के खिलाफ तैयारी की आवश्यकता पर जोर देने के लिए&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;रोग X को 2018 में डब्ल्यूएचओ के&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;प्राथमिकता वाले रोगों के ब्लूप्रिंट&lt;/span&gt;&amp;nbsp;में शामिल किया गया था।&lt;/span&gt;&lt;/li&gt;
		&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;सूची में ये भी शामिल हैं&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;इबोला, निपाह, मारबर्ग, जीका और लासा बुखार&lt;/span&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;रोग X का उद्भव:&lt;/span&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;संभावित स्रोतों में&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;जूनोटिक स्पिलओवर&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;(जानवरों से मनुष्यों में फैलने वाली बीमारियाँ), उत्परिवर्तन या प्रयोगशाला दुर्घटनाएँ शामिल हैं।&amp;nbsp;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;जलवायु परिवर्तन, वनों की कटाई और मानव-वन्यजीवों के बीच बढ़ती हुई अंतःक्रियाएँ जोखिम को बढ़ाती हैं।&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;शब्द का महत्व:&lt;/span&gt;&lt;/span&gt;
	&lt;ul&gt;
		&lt;li&gt;​&lt;span id=&quot;docs-internal-guid-1757fdea-7fff-90b9-ca67-59f8dd3b1c3f&quot;&gt;इसमें&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;निगरानी, स्वास्थ्य सेवा बुनियादी ढांचे और तेजी से वैक्सीन/निदान विकास सहित&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-weight: 700; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;वैश्विक महामारी की तैयारियों&lt;/span&gt;&amp;nbsp;&lt;span style=&quot;background-color: transparent; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternates: normal; font-variant-position: normal; font-variant-emoji: normal; vertical-align: baseline;&quot;&gt;में अंतराल को उजागर किया गया है&lt;/span&gt;।&lt;/span&gt;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;​&lt;u&gt;&lt;strong&gt;To reflect sunlight and cool the Earth&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;New study makes controversial weather-tweaking idea more realistic.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;785&quot; data-start=&quot;611&quot;&gt;
	&lt;p data-end=&quot;785&quot; data-start=&quot;613&quot;&gt;&lt;strong data-end=&quot;654&quot; data-start=&quot;613&quot;&gt;Stratospheric Aerosol Injection (SAI)&lt;/strong&gt;: Aerosols (like &lt;strong data-end=&quot;690&quot; data-start=&quot;671&quot;&gt;sulphur dioxide&lt;/strong&gt;) are sprayed into the &lt;strong data-end=&quot;729&quot; data-start=&quot;713&quot;&gt;stratosphere&lt;/strong&gt; to reflect sunlight and &lt;strong data-end=&quot;784&quot; data-start=&quot;754&quot;&gt;reduce global temperatures&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;899&quot; data-start=&quot;786&quot;&gt;
	&lt;p data-end=&quot;899&quot; data-start=&quot;788&quot;&gt;A new study in &lt;strong data-end=&quot;829&quot; data-start=&quot;803&quot;&gt;Earth&amp;rsquo;s Future journal&lt;/strong&gt; proposes a &lt;strong data-end=&quot;861&quot; data-start=&quot;841&quot;&gt;low-altitude SAI&lt;/strong&gt; using &lt;strong data-end=&quot;898&quot; data-start=&quot;868&quot;&gt;modified existing aircraft&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1017&quot; data-start=&quot;900&quot;&gt;
	&lt;p data-end=&quot;1017&quot; data-start=&quot;902&quot;&gt;SAI is &lt;strong data-end=&quot;926&quot; data-start=&quot;909&quot;&gt;controversial&lt;/strong&gt; due to its &lt;strong data-end=&quot;961&quot; data-start=&quot;938&quot;&gt;global side effects&lt;/strong&gt;, which can vary by region and aren&amp;rsquo;t always beneficial.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1097&quot; data-start=&quot;1018&quot;&gt;
	&lt;p data-end=&quot;1097&quot; data-start=&quot;1020&quot;&gt;It is a form of &lt;strong data-end=&quot;1066&quot; data-start=&quot;1036&quot;&gt;Solar Climate Intervention&lt;/strong&gt;, a type of &lt;strong data-end=&quot;1096&quot; data-start=&quot;1078&quot;&gt;geoengineering&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1364&quot; data-start=&quot;1098&quot;&gt;
	&lt;p data-end=&quot;1364&quot; data-start=&quot;1100&quot;&gt;Other methods include:&lt;br data-end=&quot;1125&quot; data-start=&quot;1122&quot; /&gt;
	&amp;rarr; &lt;strong data-end=&quot;1157&quot; data-start=&quot;1129&quot;&gt;Marine Cloud Brightening&lt;/strong&gt;: Makes clouds more reflective using sea salt.&lt;br data-end=&quot;1206&quot; data-start=&quot;1203&quot; /&gt;
	&amp;rarr; &lt;strong data-end=&quot;1236&quot; data-start=&quot;1210&quot;&gt;Space-Based Reflectors&lt;/strong&gt;: Hypothetical mirrors in space.&lt;br data-end=&quot;1271&quot; data-start=&quot;1268&quot; /&gt;
	&amp;rarr; &lt;strong data-end=&quot;1306&quot; data-start=&quot;1275&quot;&gt;Surface Albedo Modification&lt;/strong&gt;: Lightening Earth&amp;#39;s surface (e.g., painting roofs white).&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;सूर्य के प्रकाश को परावर्तित करना और पृथ्वी को ठंडा करना&amp;nbsp;&lt;/strong&gt;&lt;/u&gt;है&amp;nbsp;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;नया अध्ययन विवादास्पद मौसम-बदलने वाले विचार को और अधिक यथार्थवादी बनाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;785&quot; data-start=&quot;611&quot;&gt;
	&lt;p data-end=&quot;785&quot; data-start=&quot;613&quot;&gt;&lt;strong data-end=&quot;654&quot; data-start=&quot;613&quot;&gt;स्ट्रैटोस्फेरिक एरोसोल इंजेक्शन (SAI)&lt;/strong&gt;: एरोसोल (जैसे &lt;strong data-end=&quot;690&quot; data-start=&quot;671&quot;&gt;सल्फर डाइऑक्साइड&lt;/strong&gt;) को &lt;strong data-end=&quot;729&quot; data-start=&quot;713&quot;&gt;स्ट्रैटोस्फेयर&lt;/strong&gt; में सूर्य के प्रकाश को परावर्तित करने और &lt;strong data-end=&quot;784&quot; data-start=&quot;754&quot;&gt;वैश्विक तापमान को कम करने&lt;/strong&gt; के लिए छिड़का जाता है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;899&quot; data-start=&quot;786&quot;&gt;
	&lt;p data-end=&quot;899&quot; data-start=&quot;788&quot;&gt;&lt;strong data-end=&quot;829&quot; data-start=&quot;803&quot;&gt;अर्थ्स फ़्यूचर जर्नल&lt;/strong&gt; में एक नए अध्ययन में &lt;strong data-end=&quot;861&quot; data-start=&quot;841&quot;&gt;निम्न-ऊंचाई वाले SAI&lt;/strong&gt; का प्रस्ताव &lt;strong data-end=&quot;898&quot; data-start=&quot;868&quot;&gt;संशोधित मौजूदा विमानों&lt;/strong&gt; का उपयोग करके किया गया है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1017&quot; data-start=&quot;900&quot;&gt;
	&lt;p data-end=&quot;1017&quot; data-start=&quot;902&quot;&gt;SAI अपने &lt;strong data-end=&quot;961&quot; data-start=&quot;938&quot;&gt;वैश्विक दुष्प्रभावों&lt;/strong&gt; के कारण &lt;strong data-end=&quot;926&quot; data-start=&quot;909&quot;&gt;विवादास्पद&lt;/strong&gt; है, जो क्षेत्र के अनुसार भिन्न हो सकते हैं और हमेशा फायदेमंद नहीं होते हैं।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1097&quot; data-start=&quot;1018&quot;&gt;
	&lt;p data-end=&quot;1097&quot; data-start=&quot;1020&quot;&gt;यह &lt;strong data-end=&quot;1066&quot; data-start=&quot;1036&quot;&gt;सौर जलवायु हस्तक्षेप&lt;/strong&gt; का एक रूप है, जो &lt;strong data-end=&quot;1096&quot; data-start=&quot;1078&quot;&gt;जियोइंजीनियरिंग&lt;/strong&gt; का एक प्रकार है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1364&quot; data-start=&quot;1098&quot;&gt;
	&lt;p data-end=&quot;1364&quot; data-start=&quot;1100&quot;&gt;अन्य तरीकों में शामिल हैं:&lt;br data-end=&quot;1125&quot; data-start=&quot;1122&quot; /&gt;
	&amp;rarr; &lt;strong data-end=&quot;1157&quot; data-start=&quot;1129&quot;&gt;मरीन क्लाउड ब्राइटनिंग&lt;/strong&gt;: समुद्री नमक का उपयोग करके बादलों को अधिक परावर्तक बनाता है।&lt;br data-end=&quot;1206&quot; data-start=&quot;1203&quot; /&gt;
	&amp;rarr; &lt;strong data-end=&quot;1236&quot; data-start=&quot;1210&quot;&gt;अंतरिक्ष-आधारित परावर्तक&lt;/strong&gt;: अंतरिक्ष में काल्पनिक दर्पण।&lt;br data-end=&quot;1271&quot; data-start=&quot;1268&quot; /&gt;
	&amp;rarr; &lt;strong data-end=&quot;1306&quot; data-start=&quot;1275&quot;&gt;सतह अल्बेडो संशोधन&lt;/strong&gt;: पृथ्वी की सतह को हल्का करना (जैसे, छतों को सफेद रंग से रंगना)।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Iceberg A23a.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Iceberg A23a, the world&amp;rsquo;s largest iceberg, is drifting towards South Georgia Island and may impact its ecosystem.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;A23a weighs approximately one trillion tons and covers 400 square miles.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;It was stuck on the ocean floor near Antarctica for 37 years before detaching in 1986.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Now drifting 300 km from South Georgia Island&lt;/strong&gt;, it may get stranded or disrupt penguin and seal feeding patterns.&lt;/li&gt;
	&lt;li&gt;Scientists fear its impact on local marine ecosystems and wildlife.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt; &lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Iceberg B15:&lt;/strong&gt;&lt;/u&gt; Once the largest iceberg, it broke off Antarctica&amp;rsquo;s Ross Ice Shelf in 2000.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Iceberg C19:&lt;/strong&gt;&lt;/u&gt; A massive iceberg that broke away from the Antarctic ice sheet in 2002.&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;Iceberg D16:&lt;/strong&gt;&lt;/u&gt; A smaller iceberg known for its unusual drift patterns in Antarctic waters.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;हिमखंड A23a है।&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;हिमखंड A23a, दुनिया का सबसे बड़ा हिमखंड, दक्षिण जॉर्जिया द्वीप की ओर बढ़ रहा है और इसके पारिस्थितिकी तंत्र को प्रभावित कर सकता है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;A23a का वजन लगभग एक ट्रिलियन टन है और यह 400 वर्ग मील में फैला हुआ है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;यह 1986 में अलग होने से पहले 37 वर्षों तक अंटार्कटिका के पास समुद्र तल पर फंसा रहा।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;अब दक्षिण जॉर्जिया द्वीप से 300 किमी दूर बह रहा है&lt;/strong&gt;, यह फंस सकता है या पेंगुइन और सील के भोजन के पैटर्न को बाधित कर सकता है।&lt;/li&gt;
	&lt;li&gt;वैज्ञानिकों को स्थानीय समुद्री पारिस्थितिक तंत्र और वन्य जीवन पर इसके प्रभाव का डर है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;हिमखंड B15:&lt;/strong&gt;&lt;/u&gt; कभी सबसे बड़ा हिमखंड, यह 2000 में अंटार्कटिका के रॉस आइस शेल्फ से टूट गया था।&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;हिमखंड C19:&lt;/strong&gt;&lt;/u&gt; एक विशाल हिमखंड जो 2002 में अंटार्कटिक बर्फ की चादर से अलग हो गया था।&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;strong&gt;हिमखंड D16:&lt;/strong&gt;&lt;/u&gt; एक छोटा हिमखंड जो अंटार्कटिक जल में अपने असामान्य बहाव प्रतिरूप के लिए जाना जाता है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;option 1&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Union Animal Husbandry Ministry has urged States to quarantine animals showing symptoms of avian influenza following the deaths of three tigers and one leopard.&amp;nbsp;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;H5N1 virus: &lt;/strong&gt;It is a type of Highly Pathogenic Avian Influenza (HPAI), commonly referred to as Bird Flu. &lt;em&gt;&lt;strong&gt;Hence, option 1 is correct.&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;First case in animals in India:&lt;/strong&gt; The virus was detected in tigers and leopards, marking the first reported case of avian influenza crossing the species barrier in India.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Transmission: &lt;/strong&gt;Likely linked to the chicken served to the animals, as per preliminary findings.&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;Preventive measures: &lt;/strong&gt;The Ministry has directed enhanced biosecurity protocols, disinfection, and the isolation of infected animals to curb the spread.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;विकल्प 1&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;केंद्रीय पशुपालन मंत्रालय ने तीन बाघों और एक तेंदुए की मौत के बाद एवियन इन्फ्लूएंजा के लक्षण दिखाने वाले जानवरों को पृथक करने के लिए राज्यों से आग्रह किया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;H5N1 वायरस:&lt;/strong&gt; यह एक प्रकार का अत्यधिक रोगजनक एवियन इन्फ्लूएंजा (HPAI) है, जिसे आमतौर पर बर्ड फ्लू कहा जाता है। &lt;em&gt;&lt;strong&gt;अतः&amp;nbsp;विकल्प 1 सही है।&lt;/strong&gt;&lt;/em&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;भारत में जानवरों में पहला मामला:&lt;/strong&gt; वायरस बाघों और तेंदुओं में पाया गया, जो भारत में एवियन इन्फ्लूएंजा के प्रजातियों की बाधा को पार करने का पहला रिपोर्ट किया गया मामला है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संक्रमण:&lt;/strong&gt; प्रारंभिक निष्कर्षों के अनुसार, जानवरों को दी जाने वाली मुर्गी से जुड़ा हुआ है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;निवारक उपाय:&lt;/strong&gt; मंत्रालय ने प्रसार को रोकने के लिए उन्नत जैव सुरक्षा प्रोटोकॉल, कीटाणुशोधन और संक्रमित जानवरों के अलगाव का निर्देश दिया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;To map the Moon&amp;rsquo;s gravitational field with high precision&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;NASA&amp;rsquo;s Grail (Gravity Recovery And Interior Laboratory) Mission has unveiled significant differences between the moon&amp;rsquo;s nearside and farside.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul data-end=&quot;1123&quot; data-start=&quot;446&quot;&gt;
	&lt;li data-end=&quot;515&quot; data-start=&quot;446&quot;&gt;
	&lt;p data-end=&quot;515&quot; data-start=&quot;448&quot;&gt;&lt;strong data-end=&quot;472&quot; data-start=&quot;448&quot;&gt;NASA&amp;rsquo;s GRAIL mission&lt;/strong&gt; studied the &lt;strong data-end=&quot;514&quot; data-start=&quot;485&quot;&gt;Moon&amp;rsquo;s internal structure&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;591&quot; data-start=&quot;516&quot;&gt;
	&lt;p data-end=&quot;591&quot; data-start=&quot;518&quot;&gt;It revealed &lt;strong data-end=&quot;578&quot; data-start=&quot;530&quot;&gt;differences between the nearside and farside&lt;/strong&gt; of the Moon.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;680&quot; data-start=&quot;592&quot;&gt;
	&lt;p data-end=&quot;680&quot; data-start=&quot;594&quot;&gt;The &lt;strong data-end=&quot;610&quot; data-start=&quot;598&quot;&gt;nearside&lt;/strong&gt; (facing Earth) has a &lt;strong data-end=&quot;662&quot; data-start=&quot;632&quot;&gt;hotter, more active mantle&lt;/strong&gt; than the farside.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;752&quot; data-start=&quot;681&quot;&gt;
	&lt;p data-end=&quot;752&quot; data-start=&quot;683&quot;&gt;Due to &lt;strong data-end=&quot;709&quot; data-start=&quot;690&quot;&gt;Earth&amp;rsquo;s gravity&lt;/strong&gt;, the Moon undergoes &lt;strong data-end=&quot;751&quot; data-start=&quot;730&quot;&gt;tidal deformation&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;820&quot; data-start=&quot;753&quot;&gt;
	&lt;p data-end=&quot;820&quot; data-start=&quot;755&quot;&gt;The &lt;strong data-end=&quot;783&quot; data-start=&quot;759&quot;&gt;nearside flexes more&lt;/strong&gt;, proving it has a &lt;strong data-end=&quot;819&quot; data-start=&quot;802&quot;&gt;softer mantle&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;910&quot; data-start=&quot;821&quot;&gt;
	&lt;p data-end=&quot;910&quot; data-start=&quot;823&quot;&gt;&lt;strong data-end=&quot;844&quot; data-start=&quot;823&quot;&gt;Ancient volcanism&lt;/strong&gt; on the nearside created &lt;strong data-end=&quot;889&quot; data-start=&quot;869&quot;&gt;radioactive heat&lt;/strong&gt; (thorium, titanium).&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;989&quot; data-start=&quot;911&quot;&gt;
	&lt;p data-end=&quot;989&quot; data-start=&quot;913&quot;&gt;This formed &lt;strong data-end=&quot;947&quot; data-start=&quot;925&quot;&gt;smooth mare plains&lt;/strong&gt;, unlike the &lt;strong data-end=&quot;988&quot; data-start=&quot;960&quot;&gt;rugged farside highlands&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1068&quot; data-start=&quot;990&quot;&gt;
	&lt;p data-end=&quot;1068&quot; data-start=&quot;992&quot;&gt;GRAIL created the &lt;strong data-end=&quot;1045&quot; data-start=&quot;1010&quot;&gt;most detailed gravitational map&lt;/strong&gt; of the Moon ever made.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1123&quot; data-start=&quot;1069&quot;&gt;
	&lt;p data-end=&quot;1123&quot; data-start=&quot;1071&quot;&gt;Mission helps in planning &lt;strong data-end=&quot;1122&quot; data-start=&quot;1097&quot;&gt;future lunar missions&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1149&quot; data-start=&quot;1125&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong data-end=&quot;1146&quot; data-start=&quot;1129&quot;&gt;Mission facts&lt;/strong&gt;:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;1170&quot; data-start=&quot;1150&quot;&gt;
		&lt;p data-end=&quot;1170&quot; data-start=&quot;1152&quot;&gt;&lt;strong data-end=&quot;1162&quot; data-start=&quot;1152&quot;&gt;Agency&lt;/strong&gt;: NASA&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1210&quot; data-start=&quot;1171&quot;&gt;
		&lt;p data-end=&quot;1210&quot; data-start=&quot;1173&quot;&gt;&lt;strong data-end=&quot;1188&quot; data-start=&quot;1173&quot;&gt;Launch Date&lt;/strong&gt;: September 10, 2011&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1249&quot; data-start=&quot;1211&quot;&gt;
		&lt;p data-end=&quot;1249&quot; data-start=&quot;1213&quot;&gt;&lt;strong data-end=&quot;1228&quot; data-start=&quot;1213&quot;&gt;Orbit Start&lt;/strong&gt;: December 31, 2011&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1299&quot; data-start=&quot;1250&quot;&gt;
		&lt;p data-end=&quot;1299&quot; data-start=&quot;1252&quot;&gt;&lt;strong data-end=&quot;1259&quot; data-start=&quot;1252&quot;&gt;End&lt;/strong&gt;: December 17, 2012 (controlled crash)&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1353&quot; data-start=&quot;1300&quot;&gt;
		&lt;p data-end=&quot;1353&quot; data-start=&quot;1302&quot;&gt;&lt;strong data-end=&quot;1316&quot; data-start=&quot;1302&quot;&gt;Spacecraft&lt;/strong&gt;: Two satellites &amp;ndash; &lt;strong data-end=&quot;1351&quot; data-start=&quot;1335&quot;&gt;Ebb and Flow&lt;/strong&gt;&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1424&quot; data-start=&quot;1354&quot;&gt;
		&lt;p data-end=&quot;1424&quot; data-start=&quot;1356&quot;&gt;&lt;strong data-end=&quot;1364&quot; data-start=&quot;1356&quot;&gt;Goal&lt;/strong&gt;: Understand the Moon&amp;rsquo;s &lt;strong data-end=&quot;1424&quot; data-start=&quot;1388&quot;&gt;gravity and geological evolution&lt;/strong&gt;&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर है &lt;u&gt;&lt;strong&gt;उच्च परिशुद्धता के साथ चंद्रमा के गुरुत्वाकर्षण क्षेत्र का मानचित्रण करना&lt;/strong&gt;&lt;/u&gt;।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;NASA के Grail (ग्रेविटी रिकवरी एंड इंटीरियर लेबोरेटरी) मिशन ने चंद्रमा के पास के और दूर के हिस्से के बीच महत्वपूर्ण अंतरों का पता लगाया है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul data-end=&quot;1123&quot; data-start=&quot;446&quot;&gt;
	&lt;li data-end=&quot;515&quot; data-start=&quot;446&quot;&gt;
	&lt;p data-end=&quot;515&quot; data-start=&quot;448&quot;&gt;&lt;strong data-end=&quot;472&quot; data-start=&quot;448&quot;&gt;NASA के GRAIL मिशन&lt;/strong&gt; ने &lt;strong data-end=&quot;514&quot; data-start=&quot;485&quot;&gt;चंद्रमा की आंतरिक संरचना&lt;/strong&gt; का अध्ययन किया।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;591&quot; data-start=&quot;516&quot;&gt;
	&lt;p data-end=&quot;591&quot; data-start=&quot;518&quot;&gt;इससे चंद्रमा के &lt;strong data-end=&quot;578&quot; data-start=&quot;530&quot;&gt;पास के और दूर के हिस्से के बीच अंतर&lt;/strong&gt; का पता चला।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;680&quot; data-start=&quot;592&quot;&gt;
	&lt;p data-end=&quot;680&quot; data-start=&quot;594&quot;&gt;पास का हिस्सा (पृथ्वी के सामने वाला) दूर के हिस्से की तुलना में &lt;strong data-end=&quot;662&quot; data-start=&quot;632&quot;&gt;अधिक गर्म और अधिक सक्रिय आवरण&lt;/strong&gt; वाला है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;752&quot; data-start=&quot;681&quot;&gt;
	&lt;p data-end=&quot;752&quot; data-start=&quot;683&quot;&gt;&lt;strong data-end=&quot;709&quot; data-start=&quot;690&quot;&gt;पृथ्वी के गुरुत्वाकर्षण&lt;/strong&gt; के कारण, चंद्रमा &lt;strong data-end=&quot;751&quot; data-start=&quot;730&quot;&gt;ज्वारीय विकृति&lt;/strong&gt; से गुजरता है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;820&quot; data-start=&quot;753&quot;&gt;
	&lt;p data-end=&quot;820&quot; data-start=&quot;755&quot;&gt;पास का हिस्सा अधिक झुकता है, यह साबित करता है कि इसका &lt;strong data-end=&quot;819&quot; data-start=&quot;802&quot;&gt;नरम आवरण&lt;/strong&gt; है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;910&quot; data-start=&quot;821&quot;&gt;
	&lt;p data-end=&quot;910&quot; data-start=&quot;823&quot;&gt;&lt;strong data-end=&quot;844&quot; data-start=&quot;823&quot;&gt;प्राचीन ज्वालामुखी&lt;/strong&gt; ने पास के हिस्से में &lt;strong data-end=&quot;889&quot; data-start=&quot;869&quot;&gt;रेडियोधर्मी ऊष्मा&lt;/strong&gt; (थोरियम, टाइटेनियम) बनाई।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;989&quot; data-start=&quot;911&quot;&gt;
	&lt;p data-end=&quot;989&quot; data-start=&quot;913&quot;&gt;इससे &lt;strong data-end=&quot;947&quot; data-start=&quot;925&quot;&gt;चिकने समुद्र के मैदान&lt;/strong&gt; बने, जो &lt;strong data-end=&quot;988&quot; data-start=&quot;960&quot;&gt;उबड़-खाबड़ दूर के पहाड़ियों&lt;/strong&gt; के विपरीत हैं।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1068&quot; data-start=&quot;990&quot;&gt;
	&lt;p data-end=&quot;1068&quot; data-start=&quot;992&quot;&gt;GRAIL ने चंद्रमा का अब तक का &lt;strong data-end=&quot;1045&quot; data-start=&quot;1010&quot;&gt;सबसे विस्तृत गुरुत्वाकर्षण मानचित्र&lt;/strong&gt; बनाया।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1123&quot; data-start=&quot;1069&quot;&gt;
	&lt;p data-end=&quot;1123&quot; data-start=&quot;1071&quot;&gt;मिशन &lt;strong data-end=&quot;1122&quot; data-start=&quot;1097&quot;&gt;भविष्य के चंद्र मिशनों&lt;/strong&gt; की योजना बनाने में मदद करता है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1149&quot; data-start=&quot;1125&quot;&gt;&lt;span style=&quot;font-size:14px;&quot;&gt;&lt;strong data-end=&quot;1146&quot; data-start=&quot;1129&quot;&gt;मिशन तथ्य&lt;/strong&gt;:&lt;/span&gt;
	&lt;ul&gt;
		&lt;li data-end=&quot;1170&quot; data-start=&quot;1150&quot;&gt;
		&lt;p data-end=&quot;1170&quot; data-start=&quot;1152&quot;&gt;&lt;strong data-end=&quot;1162&quot; data-start=&quot;1152&quot;&gt;संस्था&lt;/strong&gt;: NASA&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1210&quot; data-start=&quot;1171&quot;&gt;
		&lt;p data-end=&quot;1210&quot; data-start=&quot;1173&quot;&gt;&lt;strong data-end=&quot;1188&quot; data-start=&quot;1173&quot;&gt;प्रक्षेपण तिथि&lt;/strong&gt;: 10 सितंबर, 2011&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1249&quot; data-start=&quot;1211&quot;&gt;
		&lt;p data-end=&quot;1249&quot; data-start=&quot;1213&quot;&gt;&lt;strong data-end=&quot;1228&quot; data-start=&quot;1213&quot;&gt;कक्षा प्रारंभ&lt;/strong&gt;: 31 दिसंबर, 2011&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1299&quot; data-start=&quot;1250&quot;&gt;
		&lt;p data-end=&quot;1299&quot; data-start=&quot;1252&quot;&gt;&lt;strong data-end=&quot;1259&quot; data-start=&quot;1252&quot;&gt;समाप्ति&lt;/strong&gt;: 17 दिसंबर, 2012 (नियंत्रित दुर्घटना)&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1353&quot; data-start=&quot;1300&quot;&gt;
		&lt;p data-end=&quot;1353&quot; data-start=&quot;1302&quot;&gt;&lt;strong data-end=&quot;1316&quot; data-start=&quot;1302&quot;&gt;अंतरिक्ष यान&lt;/strong&gt;: दो उपग्रह - &lt;strong data-end=&quot;1351&quot; data-start=&quot;1335&quot;&gt;Ebb और Flow&lt;/strong&gt;&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;1424&quot; data-start=&quot;1354&quot;&gt;
		&lt;p data-end=&quot;1424&quot; data-start=&quot;1356&quot;&gt;&lt;strong data-end=&quot;1364&quot; data-start=&quot;1356&quot;&gt;लक्ष्य&lt;/strong&gt;: चंद्रमा के &lt;strong data-end=&quot;1424&quot; data-start=&quot;1388&quot;&gt;गुरुत्वाकर्षण और भूवैज्ञानिक विकास&lt;/strong&gt; को समझना&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The Correct Answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;Eurobank of Cyprus&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;MoU signed to introduce UPI services in Cyprus.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;295&quot; data-start=&quot;195&quot;&gt;
	&lt;p data-end=&quot;295&quot; data-start=&quot;197&quot;&gt;&lt;strong data-end=&quot;205&quot; data-start=&quot;197&quot;&gt;NPCI&lt;/strong&gt; signed an &lt;strong data-end=&quot;223&quot; data-start=&quot;216&quot;&gt;MoU&lt;/strong&gt; with &lt;strong data-end=&quot;251&quot; data-start=&quot;229&quot;&gt;Eurobank of Cyprus&lt;/strong&gt; to launch &lt;strong data-end=&quot;278&quot; data-start=&quot;262&quot;&gt;UPI services&lt;/strong&gt; in &lt;strong data-end=&quot;292&quot; data-start=&quot;282&quot;&gt;Cyprus&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;384&quot; data-start=&quot;296&quot;&gt;
	&lt;p data-end=&quot;384&quot; data-start=&quot;298&quot;&gt;The goal is to enable &lt;strong data-end=&quot;349&quot; data-start=&quot;320&quot;&gt;cross-border transactions&lt;/strong&gt; for &lt;strong data-end=&quot;381&quot; data-start=&quot;354&quot;&gt;tourists and businesses&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;462&quot; data-start=&quot;385&quot;&gt;
	&lt;p data-end=&quot;462&quot; data-start=&quot;387&quot;&gt;This was a &lt;strong data-end=&quot;422&quot; data-start=&quot;398&quot;&gt;key business outcome&lt;/strong&gt; of &lt;strong data-end=&quot;445&quot; data-start=&quot;426&quot;&gt;PM Modi&amp;rsquo;s visit&lt;/strong&gt; to &lt;strong data-end=&quot;459&quot; data-start=&quot;449&quot;&gt;Cyprus&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;583&quot; data-start=&quot;463&quot;&gt;
	&lt;p data-end=&quot;583&quot; data-start=&quot;465&quot;&gt;&lt;strong data-end=&quot;495&quot; data-start=&quot;465&quot;&gt;NSE International Exchange&lt;/strong&gt; at &lt;strong data-end=&quot;522&quot; data-start=&quot;499&quot;&gt;GIFT City (Gujarat)&lt;/strong&gt; also signed an &lt;strong data-end=&quot;545&quot; data-start=&quot;538&quot;&gt;MoU&lt;/strong&gt; with the &lt;strong data-end=&quot;580&quot; data-start=&quot;555&quot;&gt;Cyprus Stock Exchange&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;700&quot; data-start=&quot;584&quot;&gt;
	&lt;p data-end=&quot;700&quot; data-start=&quot;586&quot;&gt;This aims to enable &lt;strong data-end=&quot;636&quot; data-start=&quot;606&quot;&gt;cross-border capital flows&lt;/strong&gt; and benefit &lt;strong data-end=&quot;662&quot; data-start=&quot;649&quot;&gt;investors&lt;/strong&gt; in &lt;strong data-end=&quot;699&quot; data-start=&quot;666&quot;&gt;GIFT City, Cyprus, and Europe&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;यूरोबैंक ऑफ़ साइप्रस&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;साइप्रस में UPI सेवाएँ शुरू करने के लिए समझौते पर हस्ताक्षर किए गए।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;font-size:22px;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; style=&quot;color: rgb(33, 37, 41);&quot; width=&quot;26px&quot; /&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&lt;span style=&quot;vertical-align: middle; &quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;295&quot; data-start=&quot;195&quot;&gt;
	&lt;p data-end=&quot;295&quot; data-start=&quot;197&quot;&gt;&lt;strong data-end=&quot;205&quot; data-start=&quot;197&quot;&gt;NPCI&lt;/strong&gt; ने &lt;strong data-end=&quot;223&quot; data-start=&quot;216&quot;&gt;समझौते&lt;/strong&gt; पर &lt;strong data-end=&quot;251&quot; data-start=&quot;229&quot;&gt;यूरोबैंक ऑफ़ साइप्रस&lt;/strong&gt; के साथ &lt;strong data-end=&quot;278&quot; data-start=&quot;262&quot;&gt;UPI सेवाएँ&lt;/strong&gt; शुरू करने के लिए &lt;strong data-end=&quot;292&quot; data-start=&quot;282&quot;&gt;साइप्रस&lt;/strong&gt; में हस्ताक्षर किए।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;384&quot; data-start=&quot;296&quot;&gt;
	&lt;p data-end=&quot;384&quot; data-start=&quot;298&quot;&gt;लक्ष्य &lt;strong data-end=&quot;349&quot; data-start=&quot;320&quot;&gt;सीमा पार लेनदेन&lt;/strong&gt; को &lt;strong data-end=&quot;381&quot; data-start=&quot;354&quot;&gt;पर्यटकों और व्यवसायों&lt;/strong&gt; के लिए सक्षम करना है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;462&quot; data-start=&quot;385&quot;&gt;
	&lt;p data-end=&quot;462&quot; data-start=&quot;387&quot;&gt;यह &lt;strong data-end=&quot;422&quot; data-start=&quot;398&quot;&gt;प्रधानमंत्री मोदी की साइप्रस यात्रा&lt;/strong&gt; का एक &lt;strong data-end=&quot;445&quot; data-start=&quot;426&quot;&gt;मुख्य व्यावसायिक परिणाम&lt;/strong&gt; था।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;583&quot; data-start=&quot;463&quot;&gt;
	&lt;p data-end=&quot;583&quot; data-start=&quot;465&quot;&gt;&lt;strong data-end=&quot;495&quot; data-start=&quot;465&quot;&gt;NSE इंटरनेशनल एक्सचेंज&lt;/strong&gt; ने &lt;strong data-end=&quot;522&quot; data-start=&quot;499&quot;&gt;GIFT सिटी (गुजरात)&lt;/strong&gt; में &lt;strong data-end=&quot;545&quot; data-start=&quot;538&quot;&gt;समझौते&lt;/strong&gt; पर &lt;strong data-end=&quot;580&quot; data-start=&quot;555&quot;&gt;साइप्रस स्टॉक एक्सचेंज&lt;/strong&gt; के साथ हस्ताक्षर किए।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;700&quot; data-start=&quot;584&quot;&gt;
	&lt;p data-end=&quot;700&quot; data-start=&quot;586&quot;&gt;इसका उद्देश्य &lt;strong data-end=&quot;636&quot; data-start=&quot;606&quot;&gt;सीमा पार पूँजी प्रवाह&lt;/strong&gt; को सक्षम करना और &lt;strong data-end=&quot;662&quot; data-start=&quot;649&quot;&gt;निवेशकों&lt;/strong&gt; को &lt;strong data-end=&quot;699&quot; data-start=&quot;666&quot;&gt;GIFT सिटी, साइप्रस और यूरोप&lt;/strong&gt; में लाभान्वित करना है।&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is&amp;nbsp;&lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;IRFC &amp;amp; IRCTC&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;251&quot; data-start=&quot;2&quot;&gt;&lt;strong data-end=&quot;56&quot; data-is-only-node=&quot;&quot; data-start=&quot;2&quot;&gt;IRCTC and IRFC have been granted &amp;#39;Navratna&amp;#39; status&lt;/strong&gt;, making them the &lt;strong data-end=&quot;120&quot; data-start=&quot;74&quot;&gt;25th and 26th Navratna CPSEs, respectively&lt;/strong&gt;. This status gives them &lt;strong data-end=&quot;175&quot; data-start=&quot;145&quot;&gt;greater financial autonomy&lt;/strong&gt;, allowing investments &lt;strong data-end=&quot;248&quot; data-start=&quot;198&quot;&gt;up to ₹1,000 crore without government approval&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;573&quot; data-start=&quot;255&quot;&gt;&lt;strong data-end=&quot;292&quot; data-is-only-node=&quot;&quot; data-start=&quot;255&quot;&gt;Navratna status is given to CPSEs&lt;/strong&gt; that meet &lt;strong data-end=&quot;341&quot; data-start=&quot;303&quot;&gt;financial and performance criteria&lt;/strong&gt;, granting them more independence in &lt;strong data-end=&quot;450&quot; data-start=&quot;378&quot;&gt;investment, expansion, joint ventures, and technology collaborations&lt;/strong&gt;. These companies can &lt;strong data-end=&quot;547&quot; data-start=&quot;472&quot;&gt;invest up to ₹1,000 crore or 15% of their net worth in a single project&lt;/strong&gt; without prior approval.&lt;/li&gt;
	&lt;li data-end=&quot;885&quot; data-start=&quot;577&quot;&gt;&lt;strong data-end=&quot;607&quot; data-is-only-node=&quot;&quot; data-start=&quot;577&quot;&gt;IRCTC, established in 1999&lt;/strong&gt;, operates under the &lt;strong data-end=&quot;652&quot; data-start=&quot;628&quot;&gt;Ministry of Railways&lt;/strong&gt; and manages &lt;strong data-end=&quot;717&quot; data-start=&quot;665&quot;&gt;online ticketing, catering, and tourism services&lt;/strong&gt;. In &lt;strong data-end=&quot;804&quot; data-start=&quot;722&quot;&gt;FY 2023-24, it reported ₹4,270.18 crore turnover and ₹3,229.97 crore net worth&lt;/strong&gt;. The Navratna status will help &lt;strong data-end=&quot;882&quot; data-start=&quot;836&quot;&gt;expand its services and improve operations&lt;/strong&gt;.&lt;/li&gt;
	&lt;li data-end=&quot;1152&quot; data-start=&quot;889&quot;&gt;&lt;strong data-end=&quot;977&quot; data-is-only-node=&quot;&quot; data-start=&quot;889&quot;&gt;IRFC, set up in 1986, finances Indian Railways&amp;#39; expansion and modernization projects&lt;/strong&gt; by &lt;strong data-end=&quot;1038&quot; data-start=&quot;981&quot;&gt;raising funds from domestic and international markets&lt;/strong&gt;. With &lt;strong data-end=&quot;1103&quot; data-start=&quot;1045&quot;&gt;Navratna status, IRFC gains more financial flexibility&lt;/strong&gt; to support railway infrastructure development.&lt;/li&gt;
	&lt;li data-end=&quot;1317&quot; data-is-last-node=&quot;&quot; data-start=&quot;1156&quot;&gt;&lt;strong data-end=&quot;1211&quot; data-is-only-node=&quot;&quot; data-start=&quot;1156&quot;&gt;Well-known Navratna companies include MTNL and RVNL&lt;/strong&gt;, showing that this status enhances &lt;strong data-end=&quot;1316&quot; data-start=&quot;1247&quot;&gt;competitiveness and self-sufficiency in public sector enterprises&lt;/strong&gt;.&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;IRFC &amp;amp; IRCTC&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt; है&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;समाचार में&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;251&quot; data-start=&quot;2&quot;&gt;&lt;strong data-end=&quot;56&quot; data-is-only-node=&quot;&quot; data-start=&quot;2&quot;&gt;IRCTC और IRFC को &amp;#39;नवरत्न&amp;#39; का दर्जा दिया गया है&lt;/strong&gt;, जिससे वे क्रमशः &lt;strong data-end=&quot;120&quot; data-start=&quot;74&quot;&gt;25वाँ और 26वाँ नवरत्न CPSE बन गए हैं&lt;/strong&gt;। इस दर्जे से उन्हें &lt;strong data-end=&quot;175&quot; data-start=&quot;145&quot;&gt;अधिक वित्तीय स्वायत्तता&lt;/strong&gt; मिलती है, जिससे वे &lt;strong data-end=&quot;248&quot; data-start=&quot;198&quot;&gt;सरकार की मंज़ूरी के बिना ₹1,000 करोड़ तक का निवेश&lt;/strong&gt; कर सकते हैं।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;मुख्य बिंदु&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;573&quot; data-start=&quot;255&quot;&gt;&lt;strong data-end=&quot;292&quot; data-is-only-node=&quot;&quot; data-start=&quot;255&quot;&gt;नवरत्न का दर्जा उन CPSE को दिया जाता है&lt;/strong&gt; जो &lt;strong data-end=&quot;341&quot; data-start=&quot;303&quot;&gt;वित्तीय और प्रदर्शन मानदंड&lt;/strong&gt; को पूरा करते हैं, जिससे उन्हें &lt;strong data-end=&quot;450&quot; data-start=&quot;378&quot;&gt;निवेश, विस्तार, संयुक्त उद्यमों और प्रौद्योगिकी सहयोग&lt;/strong&gt; में अधिक स्वतंत्रता मिलती है। ये कंपनियां &lt;strong data-end=&quot;547&quot; data-start=&quot;472&quot;&gt;पूर्व अनुमोदन के बिना एक ही परियोजना में ₹1,000 करोड़ या अपने निवल मूल्य का 15% तक निवेश&lt;/strong&gt; कर सकती हैं।&lt;/li&gt;
	&lt;li data-end=&quot;885&quot; data-start=&quot;577&quot;&gt;&lt;strong data-end=&quot;607&quot; data-is-only-node=&quot;&quot; data-start=&quot;577&quot;&gt;IRCTC, 1999 में स्थापित&lt;/strong&gt;, &lt;strong data-end=&quot;652&quot; data-start=&quot;628&quot;&gt;रेल मंत्रालय&lt;/strong&gt; के अधीन कार्य करती है और &lt;strong data-end=&quot;717&quot; data-start=&quot;665&quot;&gt;ऑनलाइन टिकटिंग, खानपान और पर्यटन सेवाओं&lt;/strong&gt; का प्रबंधन करती है। &lt;strong data-end=&quot;804&quot; data-start=&quot;722&quot;&gt;वित्त वर्ष 2023-24 में, इसने ₹4,270.18 करोड़ का कारोबार और ₹3,229.97 करोड़ का निवल मूल्य&lt;/strong&gt; दर्ज किया। नवरत्न का दर्जा &lt;strong data-end=&quot;882&quot; data-start=&quot;836&quot;&gt;अपनी सेवाओं का विस्तार करने और संचालन में सुधार करने&lt;/strong&gt; में मदद करेगा।&lt;/li&gt;
	&lt;li data-end=&quot;1152&quot; data-start=&quot;889&quot;&gt;&lt;strong data-end=&quot;977&quot; data-is-only-node=&quot;&quot; data-start=&quot;889&quot;&gt;IRFC, 1986 में स्थापित, घरेलू और अंतर्राष्ट्रीय बाजारों से धन जुटाकर&lt;/strong&gt; भारतीय रेल के विस्तार और आधुनिकीकरण परियोजनाओं को वित्तपोषित करती है। &lt;strong data-end=&quot;1103&quot; data-start=&quot;1045&quot;&gt;नवरत्न दर्जे के साथ, IRFC को रेलवे के बुनियादी ढाँचे के विकास&lt;/strong&gt; को समर्थन देने के लिए अधिक वित्तीय लचीलापन प्राप्त होता है।&lt;/li&gt;
	&lt;li data-end=&quot;1317&quot; data-is-last-node=&quot;&quot; data-start=&quot;1156&quot;&gt;&lt;strong data-end=&quot;1211&quot; data-is-only-node=&quot;&quot; data-start=&quot;1156&quot;&gt;प्रसिद्ध नवरत्न कंपनियों में MTNL और RVNL शामिल हैं&lt;/strong&gt;, जो दर्शाता है कि यह दर्जा &lt;strong data-end=&quot;1316&quot; data-start=&quot;1247&quot;&gt;सार्वजनिक क्षेत्र के उद्यमों में प्रतिस्पर्धा और आत्मनिर्भरता को बढ़ाता है&lt;/strong&gt;।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Amrit Vrishti&lt;/strong&gt;&lt;/u&gt;.&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;SBI has revised its special FD scheme, &amp;lsquo;Amrit Vrishti&amp;rsquo;, with changes to the interest rates and tenure. The new scheme will be effective from 15th April 2025.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The scheme focuses on promoting deposit mobilisation, particularly targeting senior and super-senior citizens.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;lsquo;Amrit Vrishti&amp;rsquo; offers a unique 444-day tenure with revised interest rates, including 7.55% for senior citizens and 7.65% for super-senior citizens.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;SBI also revised interest rates for other FD tenures, including a reduction in the rates for general public FDs.&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;The revised FD rates will be effective starting 15th April 2025, and the scheme offers flexibility with no application deadline.&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);  &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Senior Citizens FD Rates&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;For senior citizens, the revised FD rates vary based on the tenure, with a maximum rate of 7.50% for FDs with a tenure of 5&amp;ndash;10 years.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;अमृत वृष्टि&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;SBI ने अपनी विशेष FD योजना, &amp;lsquo;अमृत वृष्टि&amp;rsquo;, में ब्याज दरों और अवधि में बदलाव के साथ संशोधन किया है। नई योजना 15 अप्रैल 2025 से प्रभावी होगी।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;यह योजना विशेष रूप से वरिष्ठ और अति वरिष्ठ नागरिकों को लक्षित करते हुए, जमा जुटाने को बढ़ावा देने पर केंद्रित है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&amp;lsquo;अमृत वृष्टि&amp;rsquo; संशोधित ब्याज दरों के साथ एक अनूठी 444-दिवसीय अवधि प्रदान करती है, जिसमें वरिष्ठ नागरिकों के लिए 7.55% और अति वरिष्ठ नागरिकों के लिए 7.65% शामिल है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;SBI ने अन्य FD अवधियों के लिए ब्याज दरों में भी संशोधन किया है, जिसमें आम जनता के लिए FD दरों में कमी शामिल है।&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;संशोधित FD दरें 15 अप्रैल 2025 से प्रभावी होंगी, और यह योजना बिना किसी आवेदन की समय सीमा के लचीलापन प्रदान करती है।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);  &quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;वरिष्ठ नागरिक FD दरें&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;वरिष्ठ नागरिकों के लिए, संशोधित FD दरें अवधि के आधार पर भिन्न होती हैं, जिसमें 5-10 वर्षों की अवधि वाले FD के लिए अधिकतम 7.50% की दर है।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Maharashtra.&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;Maharashtra topped the medal tally at the Khelo India Youth Games 2025 with 158 medals (58 gold, 47 silver).&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;Maharashtra topped the medal tally with 158 medals, including 58 gold and 47 silver, at the Khelo India Youth Games 2025.&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;Haryana secured the second position with 117 medals, followed by Rajasthan with 60 medals.&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;Uttar Pradesh won the gold medal in boys&amp;#39; basketball, while Karnataka clinched the gold in girls&amp;#39; basketball.&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Khelo India Youth Games&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;India&amp;#39;s premier national sporting event for youth, aimed at encouraging sports and identifying talent across the country.&lt;/li&gt;
		&lt;li&gt;The games provide a platform for young athletes to showcase their skills in various sports disciplines.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Closing Ceremony&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;The Khelo India Youth Games 2025 concluded with a grand and colorful ceremony held at the Pataliputra Sports Complex, Patna.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Basketball Achievements&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;Uttar Pradesh and Karnataka&amp;#39;s victory in boys&amp;#39; and girls&amp;#39; basketball showcased their strength in the sport.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;महाराष्ट्र&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;महाराष्ट्र ने खेलो इंडिया यूथ गेम्स 2025 में 158 पदक (58 स्वर्ण, 47 रजत) के साथ पदक तालिका में शीर्ष स्थान प्राप्त किया।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;खेलो इंडिया यूथ गेम्स 2025 में महाराष्ट्र ने 158 पदकों (58 स्वर्ण और 47 रजत सहित) के साथ पदक तालिका में शीर्ष स्थान प्राप्त किया।&lt;/span&gt;&lt;/strong&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;हरियाणा ने 117 पदकों के साथ दूसरा स्थान प्राप्त किया, उसके बाद राजस्थान ने 60 पदकों के साथ तीसरा स्थान प्राप्त किया।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;उत्तर प्रदेश ने बालक बास्केटबॉल में स्वर्ण पदक जीता, जबकि कर्नाटक ने बालिका बास्केटबॉल में स्वर्ण पदक जीता।&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;खेलो इंडिया यूथ गेम्स&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;युवाओं के लिए भारत का प्रमुख राष्ट्रीय खेल आयोजन, जिसका उद्देश्य देश भर में खेलों को प्रोत्साहित करना और प्रतिभाओं की पहचान करना है।&lt;/li&gt;
		&lt;li&gt;यह खेल युवा एथलीटों को विभिन्न खेलों में अपने कौशल का प्रदर्शन करने का मंच प्रदान करते हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;समापन समारोह&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;पटना के पाटलिपुत्रा खेल परिसर में आयोजित भव्य और रंगीन समारोह के साथ खेलो इंडिया यूथ गेम्स 2025 का समापन हुआ।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;बास्केटबॉल उपलब्धियाँ&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;उत्तर प्रदेश और कर्नाटक की बालक और बालिका बास्केटबॉल में जीत ने इस खेल में उनकी ताकत का प्रदर्शन किया।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;The correct answer is &lt;u&gt;&lt;strong&gt;Bangkok, Thailand; &amp;quot;Prosperous, Resilient, and Open BIMSTEC.&amp;quot;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;The 6th BIMSTEC Summit was held in Bangkok, Thailand, on April 4th, 2025, with the theme &amp;quot;Prosperous, Resilient, and Open BIMSTEC.&amp;quot;&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;The Summit took&amp;nbsp;place in&lt;strong&gt; Bangkok, Thailand,&lt;/strong&gt; on April 4, 2025, and aims to foster regional cooperation among BIMSTEC member countries.&lt;/li&gt;
	&lt;li&gt;The theme for this year&amp;rsquo;s Summit is &amp;quot;&lt;strong&gt;Prosperous, Resilient, and Open BIMSTEC,&lt;/strong&gt;&amp;quot; focusing on economic cooperation, security, and sustainable development in the region.&lt;/li&gt;
	&lt;li&gt;The Summit provided a platform to address shared challenges and promote collective growth among member states, including India, Thailand, Bangladesh, Bhutan, Myanmar, Nepal, and Sri Lanka.&lt;/li&gt;
	&lt;li&gt;Prime Minister Narendra Modi represented India at the Summit, further strengthening the collaborative efforts in addressing common developmental and security concerns in the Bay of Bengal region.&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;BIMSTEC&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;The Bay of Bengal Initiative for Multi-Sectoral Technical and Economic Cooperation (BIMSTEC) is an international organization comprising seven countries that are dependent on the Bay of Bengal region.&lt;/li&gt;
		&lt;li&gt;Member countries: Bangladesh, Bhutan, India, Myanmar, Nepal, Sri Lanka &amp;amp; Thailand.&lt;br /&gt;
		Secretariat: Dhaka, Bangladesh.&lt;br /&gt;
		Established in 1997.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Theme of the Summit&lt;/span&gt;&lt;/u&gt;
	&lt;ul&gt;
		&lt;li&gt;The theme &amp;quot;Prosperous, Resilient, and Open BIMSTEC&amp;quot; reflects the member nations&amp;#39; goals of enhancing regional cooperation and ensuring long-term stability and growth through collective action.&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर&amp;nbsp;&lt;u&gt;&lt;strong&gt;बैंकॉक, थाईलैंड; &amp;quot;समृद्ध, लचीला, और खुला BIMSTEC&amp;quot;&lt;/strong&gt;&lt;/u&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;nbsp;है।&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;6वां BIMSTEC शिखर सम्मेलन 4 अप्रैल, 2025 को बैंकॉक, थाईलैंड में &amp;quot;समृद्ध, लचीला, और खुला BIMSTEC&amp;quot; विषय के साथ आयोजित किया जाएगा।&lt;/strong&gt;&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;यह शिखर सम्मेलन &lt;strong&gt;बैंकॉक, थाईलैंड&lt;/strong&gt; में 4 अप्रैल, 2025 को होने वाला है, और इसका उद्देश्य BIMSTEC सदस्य देशों के बीच क्षेत्रीय सहयोग को बढ़ावा देना है।&lt;/li&gt;
	&lt;li&gt;इस वर्ष के शिखर सम्मेलन की थीम &amp;quot;&lt;strong&gt;समृद्ध, लचीला, और खुला BIMSTEC&lt;/strong&gt;&amp;quot; है, जो क्षेत्र में आर्थिक सहयोग, सुरक्षा और सतत विकास पर केंद्रित है।&lt;/li&gt;
	&lt;li&gt;यह शिखर सम्मेलन साझा चुनौतियों का समाधान करने और भारत, थाईलैंड, बांग्लादेश, भूटान, म्यांमार, नेपाल और श्रीलंका सहित सदस्य राज्यों के बीच सामूहिक विकास को बढ़ावा देने के लिए एक मंच प्रदान करेगा।&lt;/li&gt;
	&lt;li&gt;प्रधान मंत्री नरेंद्र मोदी शिखर सम्मेलन में भारत का प्रतिनिधित्व करेंगे, बंगाल की खाड़ी क्षेत्र में आम विकास और सुरक्षा संबंधी चिंताओं को दूर करने में सहयोगात्मक प्रयासों को और मजबूत करेंगे।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;color: rgb(0, 0, 0);&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/additional-information-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Additional Information&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;u&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;BIMSTEC&lt;/span&gt;&lt;/u&gt;

	&lt;ul&gt;
		&lt;li&gt;बंगाल की खाड़ी पहल बहु-क्षेत्रीय तकनीकी और आर्थिक सहयोग (BIMSTEC) एक अंतर्राष्ट्रीय संगठन है जिसमें सात देश शामिल हैं जो बंगाल की खाड़ी क्षेत्र पर निर्भर हैं।&lt;/li&gt;
		&lt;li&gt;सदस्य देश: बांग्लादेश, भूटान, भारत, म्यांमार, नेपाल, श्रीलंका और थाईलैंड।&lt;br /&gt;
		सचिवालय: ढाका, बांग्लादेश।&lt;br /&gt;
		स्थापित: 1997।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
